mapper.update:
UPDATE form_section
   SET title = #{title}
 WHERE id = #{sectionId}
   AND form_id = #{formId}

mapper.delete:
DELETE FROM form_section
 WHERE id = #{sectionId}
   AND form_id = #{formId}

mapper.select:
SELECT id, form_id, order_index, title
  FROM form_section
 WHERE id = #{sectionId}
   AND form_id = #{formId}

WITH reciprocal AS ( SELECT DISTINCT r2.respondent_id AS owner_id FROM survey_response r2 JOIN form myf ON myf.id = r2.form_id WHERE myf.owner_id = #{viewerId} ), pass_counts AS ( SELECT form_id, COUNT(*)::int AS pass_count FROM survey_response WHERE quality_flag = 'pass' GROUP BY form_id ) SELECT f.id, f.owner_id, f.title, f.description, f.status, f.cost_credits, f.max_responses, f.closes_at, f.share_token FROM form f LEFT JOIN reciprocal rc ON rc.owner_id = f.owner_id LEFT JOIN pass_counts pc ON pc.form_id = f.id WHERE f.status = 'ACTIVE' AND f.owner_id != #{viewerId} AND (f.closes_at IS NULL OR f.closes_at > now()) AND COALESCE(pc.pass_count, 0) < f.max_responses AND NOT EXISTS ( SELECT 1 FROM survey_response r WHERE r.form_id = f.id AND r.respondent_id = #{viewerId} )
AND f.cost_credits <= #{maxMinutes}
AND (f.cost_credits * 8 / 10) >= #{minReward}
AND rc.owner_id IS NOT NULL
ORDER BY CASE WHEN rc.owner_id IS NOT NULL THEN 0 ELSE 1 END, COALESCE(pc.pass_count, 0)::float / f.max_responses ASC, f.created_at DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(DISTINCT f.id)::int
  FROM survey_response r
  JOIN form myf ON myf.id = r.form_id AND myf.owner_id = #{viewerId}
  JOIN form f ON f.owner_id = r.respondent_id AND f.status = 'ACTIVE'
 WHERE (f.closes_at IS NULL OR f.closes_at > now())
   AND NOT EXISTS (
        SELECT 1 FROM survey_response r2
         WHERE r2.form_id = f.id AND r2.respondent_id = #{viewerId}
   )

mapper.delete:
DELETE FROM form_question
 WHERE id = #{questionId}
   AND form_id = #{formId}

mapper.update:
UPDATE form_question
   SET order_index = #{orderIndex}
 WHERE id = #{questionId}
   AND form_id = #{formId}
